function includesAny(value, needles) {
  const text = String(value ?? "").toLowerCase();
  return needles.some((needle) => text.includes(needle));
}

function inferKpiId(row) {
  const category = String(row.category ?? "").toLowerCase();
  const submodule = String(row.submodule ?? "").toLowerCase();
  const sheet = String(row.sheet ?? "").toLowerCase();
  const label = String(row.kpi ?? "").toLowerCase();
  const combined = `${category} ${submodule} ${sheet} ${label}`;

  if (includesAny(combined, ["audit observation"])) return "kpi_audit_observations";
  if (includesAny(combined, ["court", "legal cases"])) return "kpi_legal_cases";
  if (includesAny(sheet, ["academic programs"])) return "kpi_inst_program_portfolio";
  if (includesAny(sheet, ["institutional profile"])) return "kpi_inst_profile_mix";
  if (includesAny(sheet, ["anti-ragging", "grievance"])) return "kpi_governance_grievance";
  if (includesAny(sheet, ["internal qa"])) return "kpi_governance_iqac";
  if (includesAny(sheet, ["governance structure"])) return "kpi_governance_structure";
  if (includesAny(sheet, ["diversity"])) return "kpi_governance_diversity";
  if (includesAny(sheet, ["rankings", "institute rankings"])) return "kpi_rankings_only";
  if (includesAny(sheet, ["accreditations"])) return "kpi_accreditations_only";
  if (includesAny(sheet, ["iso", "quality certifications"])) return "kpi_quality_certs_only";

  if (includesAny(sheet, ["student_profile_summary"])) return "kpi_psl_student_profile";
  if (includesAny(sheet, ["enrollment_details"])) return "kpi_psl_enrollment_details";
  if (includesAny(sheet, ["international_students"])) return "kpi_psl_international_students";
  if (includesAny(sheet, ["admission_mode"])) return "kpi_psl_admission_mode";
  if (includesAny(sheet, ["student_death_cases"])) return "kpi_psl_student_death_cases";
  if (includesAny(sheet, ["faculty_staff"])) return "kpi_psl_faculty_staff";
  if (includesAny(sheet, ["faculty_research"])) return "kpi_psl_faculty_research";
  if (includesAny(sheet, ["mission_recruitment"])) return "kpi_psl_mission_recruitment";
  if (includesAny(sheet, ["faculty_awards"])) return "kpi_psl_faculty_awards";
  if (includesAny(sheet, ["international_faculty"])) return "kpi_psl_international_faculty";
  if (includesAny(sheet, ["medical_staff_details"])) return "kpi_psl_medical_staff_details";
  if (includesAny(sheet, ["medical_staff_summary"])) return "kpi_psl_medical_summary";
  if (includesAny(sheet, ["entrepreneurship_support"])) return "kpi_psl_entrepreneurship";
  if (includesAny(sheet, ["career_services"])) return "kpi_psl_career_services";
  if (includesAny(sheet, ["counselling_services"])) return "kpi_psl_counselling_services";
  if (includesAny(sheet, ["scholarships_fellowships"])) return "kpi_psl_scholarships";
  if (includesAny(sheet, ["alumni_network"])) return "kpi_psl_alumni_network";
  if (includesAny(sheet, ["phd_alumni"])) return "kpi_psl_phd_careers";
  if (includesAny(sheet, ["placement_statistics"])) return "kpi_psl_placement_statistics";
  if (includesAny(sheet, ["top_recruiters"])) return "kpi_psl_top_recruiters";
  if (includesAny(combined, ["placement", "alumni"])) return "kpi_psl_placements_alumni";

  if (includesAny(sheet, ["patents", "innovation_ip_data", "ip_commercialization"])) return "kpi_research_patents";
  if (includesAny(sheet, ["research_grants", "foreign_funding_grants", "rd_expenditure", "fundraising_investment"])) return "kpi_research_budget";
  if (includesAny(sheet, ["honors_fellowships", "research_mous", "research_awards", "intl_collaborations", "research_staff"])) return "kpi_research_collab_drill";
  if (includesAny(sheet, ["coe_industry", "faculty_consultancy", "industrial_grants", "industrial_projects", "industry_research_summary", "phd_industry_funded", "tech_transfers"])) return "kpi_research_collab";
  if (includesAny(sheet, ["startup", "hackathons", "iit_stake", "tech_biz_incubators"])) return "kpi_research_patents";
  if (category.includes("research")) return "kpi_research_overview";

  if (includesAny(sheet, ["co_collaboration_details"])) return "kpi_outreach_collab_drill";
  if (includesAny(sheet, ["co_mous_summary"])) return "kpi_outreach_collab";
  if (includesAny(sheet, ["co_events_summary", "co_partnerships_outreach", "co_intl_conferences"])) return "kpi_outreach_events";
  if (includesAny(sheet, ["co_joint_programs", "co_pmrf_program"])) return "kpi_outreach_programs";
  if (includesAny(sheet, ["co_pmrf_scholar_details"])) return "kpi_outreach_programs_drill";
  if (category.includes("collaboration")) return "kpi_outreach_collab";

  if (includesAny(label, ["utilisation rate", "utilization rate", "occupancy rate"])) return "kpi_budget_utilisation";
  if (includesAny(sheet, ["funding_financials", "internal_revenue"])) return "kpi_total_budget";
  if (includesAny(sheet, ["academic_infrastructure", "hostel_infrastructure", "infrastructure_summary"])) return "kpi_infra_budget";
  if (includesAny(sheet, ["ongoing_infrastructure_projects", "endowment_fund", "hefa_loan_details"])) return "kpi_infra_budget_drill";
  if (includesAny(sheet, ["foreign_funding", "industry_csr_funds", "institutional_awards"])) return "kpi_infra_collab_drill";
  if (category.includes("infrastructure")) return "kpi_infra_budget";

  return null;
}

function chartFamily(chart) {
  const value = String(chart ?? "").toLowerCase();
  if (value.includes("line")) return "trend";
  if (value.includes("pie") || value.includes("donut")) return "breakdown";
  if (value.includes("table")) return "table";
  return "bar";
}

function uniqueById(list) {
  const seen = new Set();
  return list.filter((item) => {
    if (!item?.id || seen.has(item.id)) return false;
    seen.add(item.id);
    return true;
  });
}

export function buildCompareHierarchy() {
  const modules = [];
  const moduleMap = new Map();

  MAPPING_ROWS.forEach((row) => {
    const kpiId = inferKpiId(row);
    const kpi = KPI_BY_ID[kpiId] ?? null;
    const module = moduleMap.get(row.categoryId) ?? {
      id: row.categoryId,
      label: row.category,
      description: row.category,
      children: [],
      submodules: [],
    };
    if (!moduleMap.has(row.categoryId)) {
      moduleMap.set(row.categoryId, module);
      modules.push(module);
    }

    let submodule = module.submodules.find((item) => item.id === row.submoduleId);
    if (!submodule) {
      submodule = {
        id: row.submoduleId,
        label: row.submodule,
        helper: `${row.category} > ${row.submodule}`,
        moduleId: row.categoryId,
        sheets: [],
        worksheets: [],
      };
      module.submodules.push(submodule);
      module.children.push(submodule);
    }

    let sheet = submodule.sheets.find((item) => item.id === row.sheetId);
    if (!sheet) {
      sheet = {
        id: row.sheetId,
        label: row.sheet,
        moduleId: row.categoryId,
        submoduleId: row.submoduleId,
        submoduleLabel: row.submodule,
        kpis: [],
      };
      submodule.sheets.push(sheet);
    }

    const compareItem = {
      id: row.id,
      label: row.kpi || row.sheet,
      kpiLabel: row.kpi || row.sheet,
      sheetId: row.sheetId,
      sheetLabel: row.sheet,
      moduleId: row.categoryId,
      moduleLabel: row.category,
      categoryLabel: row.category,
      submoduleId: row.submoduleId,
      submoduleLabel: row.submodule,
      kpiId,
      kpi,
      comparable: Boolean(kpi && ["number", "pct"].includes(kpi.format ?? "")),
      scaleEligible: Boolean(kpi && ["number", "pct"].includes(kpi.format ?? "")),
      preferredVisual: chartFamily(row.chart),
      xAxis: row.xAxis,
      yAxis: row.yAxis,
      pathway: row.pathway,
      helper: row.description || `${row.sheet}: ${row.kpi}`,
      measureFields: row.measureFields,
      dataType: row.dataType,
      notes: row.notes,
    };
    sheet.kpis.push(compareItem);
    submodule.worksheets.push(compareItem);
  });

  modules.forEach((module) => {
    module.submodules.forEach((submodule) => {
      submodule.sheets = uniqueById(submodule.sheets).map((sheet) => ({
        ...sheet,
        kpis: uniqueById(sheet.kpis),
      }));
      submodule.worksheets = uniqueById(submodule.worksheets);
    });
  });

  return modules;
}

export const COMPARE_HIERARCHY = buildCompareHierarchy();
